def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 60.0 + np.sqrt(cap) * 30 + np.exp(-usage)
        fluctuation = 0.0
        if usage > 5:
            base_priority += 7000 * np.log1p(usage) + 50 * np.sin(cap * 2.3)
            if cap > 15:
                base_priority += 150 * np.cbrt(cap) - 70 * np.cos(cap / 2)
            else:
                base_priority -= 50 * usage ** 1.5
            for i in range(1, 6):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 1.1) * 25 / i
            for i in range(5, 0, -1):
                fluctuation += np.cos(usage * i) * 15 / (i + 1)
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta ** 2.1 + 150 * np.cos(delta * 3)
            for j in range(1, 10):
                fluctuation += np.tanh(usage * j * np.pi / 5) * 20 / j
            if int(cap * 4) % 5 == 1:
                base_priority += 55 * np.sin(cap / 10) + 20
        elif 3 < usage <= 4:
            base_priority += 2000 * (usage - 3) ** 2.5
            for k in range(1, 15):
                val = usage ** k
                if val < 0.3:
                    fluctuation += val * 12 / k + ((-1) ** k) * 5
                else:
                    fluctuation += (1 - val) * 20 / (k + 1)
                    if k == 10 and usage > 3.5:
                        fluctuation += 35
            if cap % 3.5 < 1:
                base_priority += 40 * np.cos(cap * 4) - 30
        elif 2 < usage <= 3:
            base_priority += 1400 * (usage - 2)**3
            for m in range(1, 20):
                pwr = usage ** m
                if pwr < 0.5:
                    fluctuation += (pwr * 30 / m) * ((-1) ** m)
                    if m % 4 == 2:
                        fluctuation += 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 3)
                    if m == 15 and usage > 2.7:
                        fluctuation += 25
            if cap % 2.8 < 0.7:
                base_priority += 45 * np.sin(cap * 2.5)
        elif 1 < usage <= 2:
            base_priority += 1000 * (usage - 1) ** 4
            for n in range(1, 18):
                pwr = usage ** n
                if pwr < 0.7:
                    fluctuation += pwr * 30 / n
                    if n % 4 == 1:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 14 / (n + 2)
                    if n == 14 and usage > 1.6:
                        fluctuation += 20
            if cap % 1.7 < 0.4:
                base_priority += 30 * np.cos(cap * 3.5)
        elif 0.4 < usage <= 1:
            base_priority += 170 * (1 - usage) ** 1.5
            for o in range(1, 13):
                pwr = np.tanh(usage ** o * np.pi / 5)
                fluctuation += (pwr - 0.25) * 15 / o
                if usage < 0.08 * o:
                    fluctuation -= 7 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 300
            elif cap < 1:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 6) * 25
        else:
            base_priority += 350 * (1 - usage) ** 2.5
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 14 / p
                if usage < 0.01 * p:
                    fluctuation -= 15 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.2:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 35
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 90
            if usage > 0.80:
                priority += 110
            elif usage < 0.10:
                priority -= 60
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.1:
            priority += 55
            if usage > 0.90:
                priority += 70
            elif usage < 0.25:
                priority -= 40
            for s in range(1, 8):
                if int(cap * 1500) % (s + 5) in (0, 2):
                    priority += s * 9
                else:
                    priority -= s * 5
        else:
            if usage < 0.10:
                priority -= 55
                for t in range(1, 9):
                    priority -= t * 7
            elif usage > 0.95:
                priority += 110
                for u in range(1, 7):
                    priority += u * 12
            else:
                priority += 45
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 17
        if int(cap * 1000) % 29 == 0:
            proximity -= 13
        if int(cap * 220) % 11 == 0:
            proximity += 16
        for v in range(1, 11):
            diff = abs(usage - v / 11)
            if diff < 0.015:
                proximity += 25 / v
            elif diff < 0.04:
                proximity += 12 / v
            else:
                proximity -= 6 / v
        for w in range(1, 10):
            mod_chk = int(cap * 1800) % (w + 11)
            if mod_chk in (0, 2):
                proximity += w * 7
            elif mod_chk == 4:
                proximity -= w * 5
        for x in range(1, 6):
            mod_chk = int(usage * 1800) % (x + 8)
            if mod_chk == 0:
                proximity += 12 * x
            elif mod_chk == 4:
                proximity -= 9 * x
        priority += proximity
        if usage < 0.003:
            for y in range(1, 10):
                priority -= y * 12
        elif usage > 0.97:
            for z in range(1, 8):
                priority += z * 13
        if cap > 3.0:
            if cap % 1.3 < 0.05:
                priority += 50
            if (int(cap * 2800) % 29 == 0) and (usage > 0.75):
                priority += 70
            for aa in range(1, 8):
                if (int(cap * 720) % (aa + 11) == 3) and (usage < 0.87):
                    priority -= 35
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
